mapper.update:
UPDATE t_oa_invoice
SET deleted_flag = #{deletedFlag}
WHERE invoice_id = #{invoiceId}

mapper.select:
SELECT *
FROM t_oa_invoice
WHERE enterprise_id = #{enterpriseId}
AND account_number = #{accountNumber}
AND deleted_flag = #{deletedFlag}

    AND invoice_id != #{excludeInvoiceId}

SELECT oi.*,
oe.enterprise_name
FROM t_oa_invoice oi
LEFT JOIN t_oa_enterprise oe ON oi.enterprise_id = oe.enterprise_id

    oi.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(oi.invoice_heads,#{queryForm.keywords}) OR INSTR(oi.account_number,#{queryForm.keywords}) OR
        INSTR(oi.create_user_name,#{queryForm.keywords}))


        AND DATE_FORMAT(oi.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(oi.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND oi.disabled_flag = #{queryForm.disabledFlag}


        AND oi.enterprise_id = #{queryForm.enterpriseId}



    ORDER BY oi.create_time DESC

SELECT oi.*,
       oe.enterprise_name
FROM t_oa_invoice oi
LEFT JOIN t_oa_enterprise oe ON oi.enterprise_id = oe.enterprise_id
WHERE oi.invoice_id = #{invoiceId}
  AND oi.deleted_flag = #{deletedFlag}
